import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"景山公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/jingshan-park.md","filePath":"parks/jingshan-park.md","lastUpdated":1784712887000}'),o={name:"parks/jingshan-park.md"};function n(d,t,i,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="景山公园" tabindex="-1">景山公园 <a class="header-anchor" href="#景山公园" aria-label="Permalink to &quot;景山公园&quot;">​</a></h1><blockquote><p>&quot;京华览胜第一处，俯瞰紫禁城的最佳位置。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>景山公园位于北京内城南北中轴线的中心，南接故宫神武门，北对鼓楼，是明、清两代的皇家御苑。景山原名&quot;万岁山&quot;，是元、明、清三代的皇家园林。公园中心的景山是人工堆砌而成，是北京内城的制高点，也是俯瞰紫禁城的最佳位置。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:30-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">2元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳时间</strong></td><td style="text-align:left;">日出、日落时分</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线什刹海站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区景山前街44号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="元代" tabindex="-1">元代 <a class="header-anchor" href="#元代" aria-label="Permalink to &quot;元代&quot;">​</a></h3><p>景山所在位置在元代为大都城内的小丘，名&quot;青山&quot;。元世祖忽必烈曾在此堆土成山，作为元大都的&quot;镇山&quot;。</p><h3 id="明代" tabindex="-1">明代 <a class="header-anchor" href="#明代" aria-label="Permalink to &quot;明代&quot;">​</a></h3><p>明永乐年间，为营建紫禁城，在此堆放挖护城河的泥土和拆除元宫殿的渣土，堆积成山，名&quot;万岁山&quot;，又称&quot;煤山&quot;。</p><h3 id="清代" tabindex="-1">清代 <a class="header-anchor" href="#清代" aria-label="Permalink to &quot;清代&quot;">​</a></h3><p>清顺治十二年（1655年），改名&quot;景山&quot;。乾隆年间大规模扩建，形成今日规模。</p><h3 id="崇祯自缢" tabindex="-1">崇祯自缢 <a class="header-anchor" href="#崇祯自缢" aria-label="Permalink to &quot;崇祯自缢&quot;">​</a></h3><p>明崇祯十七年（1644年），李自成农民军攻入北京，崇祯皇帝朱由检仓皇出逃，在煤山东麓的一棵槐树下自缢身亡，明朝灭亡。</p><h2 id="园林布局" tabindex="-1">园林布局 <a class="header-anchor" href="#园林布局" aria-label="Permalink to &quot;园林布局&quot;">​</a></h2><p>景山公园主要景点沿中轴线分布，包括山门、绮望楼、五方亭、寿皇殿等。</p><h3 id="五方亭" tabindex="-1">五方亭 <a class="header-anchor" href="#五方亭" aria-label="Permalink to &quot;五方亭&quot;">​</a></h3><p>景山五峰之上，各建一亭，合称&quot;五方亭&quot;。</p><table tabindex="0"><thead><tr><th style="text-align:left;">亭子</th><th style="text-align:left;">位置</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>万春亭</strong></td><td style="text-align:left;">主峰（中峰）</td><td style="text-align:left;">最高最大，供奉佛像</td></tr><tr><td style="text-align:left;"><strong>观妙亭</strong></td><td style="text-align:left;">东一峰</td><td style="text-align:left;">供奉铜佛</td></tr><tr><td style="text-align:left;"><strong>周赏亭</strong></td><td style="text-align:left;">东二峰</td><td style="text-align:left;">供奉关帝</td></tr><tr><td style="text-align:left;"><strong>富览亭</strong></td><td style="text-align:left;">西一峰</td><td style="text-align:left;">供奉铜佛</td></tr><tr><td style="text-align:left;"><strong>辑芳亭</strong></td><td style="text-align:left;">西二峰</td><td style="text-align:left;">供奉财神</td></tr></tbody></table><p><strong>万春亭</strong>是景山的制高点，海拔88.35米，是俯瞰紫禁城的最佳位置。</p><h3 id="寿皇殿" tabindex="-1">寿皇殿 <a class="header-anchor" href="#寿皇殿" aria-label="Permalink to &quot;寿皇殿&quot;">​</a></h3><p>寿皇殿位于景山北麓，是供奉清代皇帝先祖神像的地方。建筑形制仿太庙，规模宏大。</p><h3 id="绮望楼" tabindex="-1">绮望楼 <a class="header-anchor" href="#绮望楼" aria-label="Permalink to &quot;绮望楼&quot;">​</a></h3><p>绮望楼位于景山南麓，是登山的入口。楼名取自&quot;登高远望&quot;之意。</p><h3 id="崇祯自缢处" tabindex="-1">崇祯自缢处 <a class="header-anchor" href="#崇祯自缢处" aria-label="Permalink to &quot;崇祯自缢处&quot;">​</a></h3><p>位于景山东麓，原有一棵老槐树，是崇祯皇帝自缢的地方。现在的槐树是后来补种的，原树在文革中被砍。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="崇祯皇帝殉国" tabindex="-1">崇祯皇帝殉国 <a class="header-anchor" href="#崇祯皇帝殉国" aria-label="Permalink to &quot;崇祯皇帝殉国&quot;">​</a></h3><p>1644年3月19日，李自成率领的农民军攻入北京。崇祯皇帝在皇宫中鸣钟召集百官，竟无人上朝。绝望之下，崇祯手持宝剑杀死了自己的女儿昭仁公主（长平公主被砍断一臂未死），又逼迫皇后周氏自尽。</p><p>随后，崇祯带着太监王承恩出东华门，直奔朝阳门，欲逃往成国公朱纯臣处避难，但未能进入。又奔安定门，城门已被封锁。走投无路之下，只得返回皇宫。</p><p>凌晨时分，崇祯带着王承恩登上煤山，在一棵槐树下自缢身亡，时年34岁。王承恩也在旁自缢殉主。</p><p>崇祯死前在衣襟上留下遗书：</p><blockquote><p>&quot;朕自登极十七年，虽朕薄德匪躬，上干天咎，然皆诸臣误朕。朕死无面目见祖宗于地下，自去冠冕，以发覆面。任贼分裂朕尸，勿伤百姓一人。&quot;</p></blockquote><p>李自成入城后，发现了崇祯的尸体，以门板装殓，停放在东华门外。三天后，才草草安葬。</p><h3 id="老槐树的故事" tabindex="-1">老槐树的故事 <a class="header-anchor" href="#老槐树的故事" aria-label="Permalink to &quot;老槐树的故事&quot;">​</a></h3><p>崇祯自缢的那棵老槐树，后来被称为&quot;罪槐&quot;。清代，这棵树被铁链锁住，以示对明朝灭亡的惩戒。</p><p>这棵老槐树一直存活到1960年代，在文革中被砍。现在的槐树是后来补种的，树龄仅几十年。</p><h3 id="景山的镇山之说" tabindex="-1">景山的镇山之说 <a class="header-anchor" href="#景山的镇山之说" aria-label="Permalink to &quot;景山的镇山之说&quot;">​</a></h3><p>传说元世祖忽必烈营建大都时，命人堆土成山，作为&quot;镇山&quot;，以镇压北京城的风水。明永乐年间扩建紫禁城，又将渣土堆于此山，使其更加高大。</p><h3 id="煤山名称的由来" tabindex="-1">煤山名称的由来 <a class="header-anchor" href="#煤山名称的由来" aria-label="Permalink to &quot;煤山名称的由来&quot;">​</a></h3><p>明代称景山为&quot;煤山&quot;，有人说是因为山中埋藏煤炭，以备不时之需；也有人说是因为山上堆满渣土，形似煤堆。后一种说法更为可信。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="最佳游览时间" tabindex="-1">最佳游览时间 <a class="header-anchor" href="#最佳游览时间" aria-label="Permalink to &quot;最佳游览时间&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>日出</strong></td><td style="text-align:left;">看太阳从紫禁城升起</td></tr><tr><td style="text-align:left;"><strong>日落</strong></td><td style="text-align:left;">看夕阳中的紫禁城</td></tr><tr><td style="text-align:left;"><strong>夜景</strong></td><td style="text-align:left;">看紫禁城灯光（仅周五、周六及节假日亮灯）</td></tr><tr><td style="text-align:left;"><strong>雪天</strong></td><td style="text-align:left;">看&quot;紫禁城雪景&quot;</td></tr></tbody></table><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约1-1.5小时）</strong>：</p><p>南门 → 绮望楼 → 登山 → 万春亭（俯瞰紫禁城） → 观妙亭 → 周赏亭 → 富览亭 → 辑芳亭 → 下山 → 寿皇殿 → 崇祯自缢处 → 东门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳拍摄点</strong>：万春亭正前方，可俯瞰整个紫禁城</li><li><strong>日出日落</strong>：如想看日出日落，需提前查看时间，公园开门/关门时间随季节调整</li><li><strong>避开人流</strong>：早上7点前或下午4点后，避开旅行团</li><li><strong>门票便宜</strong>：门票仅2元，是北京最便宜的景点之一</li><li><strong>周边游览</strong>：南门紧邻故宫北门，可安排在一起</li></ol><h3 id="与故宫的关系" tabindex="-1">与故宫的关系 <a class="header-anchor" href="#与故宫的关系" aria-label="Permalink to &quot;与故宫的关系&quot;">​</a></h3><p>景山与故宫紧密相连，南门正对故宫神武门。游览完故宫后，从神武门出，直接进入景山公园，登上万春亭俯瞰紫禁城全景，是很多游客的必选项目。</p><h2 id="四季景色" tabindex="-1">四季景色 <a class="header-anchor" href="#四季景色" aria-label="Permalink to &quot;四季景色&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">春</td><td style="text-align:left;">牡丹花展，万春亭周围牡丹盛开</td></tr><tr><td style="text-align:left;">夏</td><td style="text-align:left;">绿树成荫，避暑纳凉</td></tr><tr><td style="text-align:left;">秋</td><td style="text-align:left;">柿子、海棠果成熟，硕果累累</td></tr><tr><td style="text-align:left;">冬</td><td style="text-align:left;">雪后登顶，看&quot;紫禁城雪景&quot;</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>景山不仅是一座公园，更是明王朝灭亡的见证。崇祯皇帝殉国的故事，至今仍让人唏嘘。</p><p>同时，景山也是北京城的风水宝地。它位于北京内城的中轴线上，与故宫、天安门、正阳门、永定门连成一线，是北京城规划的重要组成部分。</p><hr><p><strong>📍 地址</strong>：北京市西城区景山前街44号 <strong>📞 电话</strong>：010-64044071 <strong>🌐 官网</strong>：<a href="http://www.jingshanpark.com" target="_blank" rel="noreferrer">www.jingshanpark.com</a></p>',59)])])}const q=a(o,[["render",n]]);export{f as __pageData,q as default};
